#include <iostream>
#include <iomanip>
#include <vector>

using namespace std;

int main() {
    int N;
    cin >> N;

    // Build the matrix bottom-up with snake pattern
    vector<vector<int>> mat(N, vector<int>(N));
    int val = 1;
    for (int r = N - 1; r >= 0; --r) {
        if ((N - 1 - r) % 2 == 0) {
            // left to right
            for (int c = 0; c < N; ++c) {
                mat[r][c] = val++;
            }
        } else {
            // right to left
            for (int c = N - 1; c >= 0; --c) {
                mat[r][c] = val++;
            }
        }
    }

    // Output with width 3
    for (int r = 0; r < N; ++r) {
        for (int c = 0; c < N; ++c) {
            cout << setw(3) << mat[r][c];
        }
        cout << '\n';
    }

    return 0;
}
